 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { Label } from '@patternfly/react-core';
 8	import { getPlanPreserveIP } from '@utils/crds/plans/selectors';
 9	
10	import type { EditableDetailsItemProps } from '../../../utils/types';
11	
12	import EditPlanPreserveStaticIPs from './EditPlanPreserveStaticIPs';
13	
14	const PreserveStaticIPsDetailsItem: FC<EditableDetailsItemProps> = ({
15	  canPatch,
16	  plan,
17	  shouldRender,
18	}) => {
19	  const { t } = useForkliftTranslation();
20	  const { showModal } = useModal();
21	
22	  if (!shouldRender) return null;
23	
24	  const preserveStaticIPs = getPlanPreserveIP(plan);
25	
26	  return (
27	    <DetailsItem
28	      title={t('Preserve static IPs')}
29	      content={
30	        <Label isCompact color="grey">
31	          {preserveStaticIPs ? t('Preserve static IPs') : t('Do not preserve static IPs')}
32	        </Label>
33	      }
34	      helpContent={t(`Preserve the static IPs of virtual machines migrated from vSphere.`)}
35	      crumbs={['spec', 'preserveStaticIPs']}
36	      onEdit={() => {
37	        showModal(<EditPlanPreserveStaticIPs resource={plan} />);
38	      }}
39	      canEdit={canPatch && isPlanEditable(plan)}
40	    />
41	  );
42	};
43	
44	export default PreserveStaticIPsDetailsItem;

